#!/usr/bin/env node
// Copy canonical Tauri launcher assets into the generated Android tree.

import { cpSync, existsSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const appDir = dirname(dirname(fileURLToPath(import.meta.url)));
const sourceDir = join(appDir, 'src-tauri/icons/android');
const generatedResDir = join(appDir, 'src-tauri/gen/android/app/src/main/res');

if (!existsSync(sourceDir)) {
  console.error(`[patch-android-icons] not found: ${sourceDir}`);
  process.exit(1);
}

if (!existsSync(generatedResDir)) {
  console.error(
    `[patch-android-icons] not found: ${generatedResDir}\nRun \`tauri android init\` first.`,
  );
  process.exit(1);
}

cpSync(sourceDir, generatedResDir, { recursive: true });
console.log('[patch-android-icons] synced Android launcher icons.');
